// // This module implements a 16-bit down-counter with an enable signal. When enabled, the counter decrements by 1 on every positive clock edge. The counter has an asynchronous clear signal that resets the counter to 0 when asserted.
module top_module(
	input clk,
	input clr,
	input ena,
	output reg [15:0] q);always @(posedge clk or posedge clr) begin
		if (clr)
			q <= 16'b0;
		else if (ena)
			q <= q + 1;
	end
endmodule
